#include "clustering/PlacementHierarchy.h"
#include <algorithm>
#include <cmath>
#include <numeric>
static HierarchyLevel fromGraph(int idx,const DynamicClusterHypergraph&g){HierarchyLevel l; l.level_index=idx; l.clusters=g.clusters(); l.nets=g.nets(); return l;}
void PlacementHierarchy::build(const PlacementDB& db,int current){levels_.clear(); DynamicClusterHypergraph g(db); levels_.push_back(fromGraph(0,g)); const double ref=g.activeMovableArea(); int threshold=current*current; int idx=0; while(g.activeMovableClusterCount()>threshold){int input=g.activeMovableClusterCount(); int target=(int)std::ceil(input/5.0); ModifiedBestChoiceClusterer cl; auto stats=cl.cluster(g,target); HierarchyLevel next=fromGraph(idx+1,g); next.stats=stats; next.area_conservation_error=std::abs(g.activeMovableArea()-ref); next.fine_to_coarse.assign(levels_.back().clusters.size(),-1); for(auto& fc:levels_.back().clusters) if(fc.active){for(auto& cc:g.clusters()) if(cc.active && std::includes(cc.original_cell_ids.begin(),cc.original_cell_ids.end(),fc.original_cell_ids.begin(),fc.original_cell_ids.end())){next.fine_to_coarse[fc.id]=cc.id; break;}} next.mapping_complete=true; for(auto& fc:levels_.back().clusters) if(fc.active&&fc.movable&&(fc.id>=(int)next.fine_to_coarse.size()||next.fine_to_coarse[fc.id]<0)) next.mapping_complete=false; next.coarse_to_fine.assign(g.clusters().size(),{}); for(size_t i=0;i<next.fine_to_coarse.size();++i) if(next.fine_to_coarse[i]>=0) next.coarse_to_fine[next.fine_to_coarse[i]].push_back((int)i); next.fixed_preserved=true; for(auto& c:g.clusters()) if(c.active&&!c.movable && c.original_cell_ids.size()!=1) next.fixed_preserved=false; levels_.push_back(next); idx++; if(stats.positive_score_merges==0||stats.stop_reason!="stopped_by_target") break; }
}
